import { BrowserRouter, Routes, Route, Link } from "react-router-dom";

function Login() {
    return (
        <div style={{padding: 24}}>
            <h2>Login page</h2>
            <p>Nếu thấy trang này, Router đã chạy đúng.</p>
            <Link to="/">Về Home</Link>
        </div>
    );
}

function Home() {
    return (
        <div style={{padding: 24}}>
            <h2>Home</h2>
            <Link to="/login">Đi tới Login</Link>
        </div>
    );
}

export default function App() {
    return (
        <BrowserRouter>
            <Routes>
                <Route path="/" element={<Home/>}/>
                <Route path="/login" element={<Login/>}/>
            </Routes>
        </BrowserRouter>
    );
}
